const a={name:"Libbsticka",icon:"libbsticka",category:"kryddor",family:"Flockblommiga",familyLatin:"Apiaceae",perennial:!0,lifespan:"10-20+ år",difficulty:"Enkel",difficultyWhy:"Libbsticka är en av de mest lättskötta kryddväxterna du kan ha. Extremt härdig, klarar alla svenska zoner, växer som ogräs och ger massvis med blad utan att kräva mycket till. Den enda utmaningen? Att hålla henne i schack - en etablerad libbsticka kan bli 2 meter hög!",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:[1,2,3,4,5,6,7,8],greenhouse:null},days:"75-90 (bladskörd från år 1, full skörd år 2)",spacing:"40-60 cm",rowSpacing:"60-90 cm",depth:"1-2 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun-half",detail:"Libbsticka trivs i full sol men tolererar halvskugga utmärkt. Faktum är att bladen smakar mildare och sötare i halvskugga, medan full sol ger mer intensiv arom. Perfekt växt för den där lite skuggiga hörnan där inget annat vill växa."},temperature:{min:-35,max:30,ideal:"15-25°C",detail:"Stenhård! Libbsticka klarar ner till -35°C utan problem. Hon är en av Sveriges härdigaste kryddväxter och övervintrar pålitligt i alla zoner. På våren är hon en av de första att sticka upp - ofta redan i mars i södra Sverige."},wind:{level:"Tålig",detail:"Libbstickans kraftiga, ihåliga stammar kan nå 2 meter och svaja i blåsten. Hon klarar vind men uppskattar ett skyddat läge - framför allt för att höga stammar inte ska knäckas. Kan behöva stöd i blåsiga lägen."}},watering:{need:"Medel",icon:"water",summary:"Libbsticka har en djup pålrot och är ganska torktålig när hon väl etablerat sig. Men hon föredrar jämnt fuktig jord - torka ger bittra blad. Tänk skogsglänta: aldrig knastertorrt, aldrig vattensjukt.",phases:[{phase:"Etablering (år 1)",need:"Medel",tip:"Håll jämnt fuktigt det första året så roten hittar ner ordentligt. Mulcha gärna runt plantan."},{phase:"Etablerad planta (sommar)",need:"Låg-Medel",tip:"Den djupa pålroten hittar vatten på egen hand. Vattna bara vid långvarig torka. Torrt väder ger tyvärr bittra blad - om du vill ha fin smak, ge lite extra vid hetta."},{phase:"Vinter",need:"Låg",tip:"Plantan är nerklipt och vilar under marken. Ingen vattning behövs."}],mistakes:["Vattensjuk jord - libbsticka har djup pålrot som ruttnar i stående vatten","Låter jorden torka ut helt under sommaren - bladen blir bittra och dåliga att använda som krydda","Glömmer att vattna under första året - etableringsperioden är viktig"],tip:"Mulcha med kompost eller gräsklipp runt plantan. Håller fukten jämn, matar jorden sakta och förbättrar jordstrukturen - allt libbsticka älskar."},soil:"Djup, mullrik och väldränerad jord. Libbsticka trivs bäst i näringsrik lerjord men klarar de flesta jordar. Det viktigaste är att jorden är djup nog för hennes imponerande pålrot.",soilTips:["Gräv ordentligt djupt vid plantering - pålroten vill ner minst 30-40 cm","Blanda in rikligt med kompost i planteringsgropen - libbsticka är en storätare jämfört med de flesta kryddor","Mulcha varje vår med en tjock giva kompost - hon tackar med frodigare tillväxt","Fungerar i kruka men välj en rejält djup (minst 40 cm) - annars trivs hon inte"],timeline:{1:[{phase:"Förodling inomhus",months:"Mars-april",icon:"indoor"},{phase:"Utplantering/direktsådd",months:"Maj",icon:"seedling"},{phase:"Bladskörd löpande",months:"Maj-okt",icon:"harvest"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Fröskörd",months:"Aug-sep",icon:"seed"}],4:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering/direktsådd",months:"Maj-jun",icon:"seedling"},{phase:"Bladskörd löpande",months:"Jun-sep",icon:"harvest"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Fröskörd",months:"Sep",icon:"seed"}],6:[{phase:"Förodling inomhus",months:"April",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Bladskörd löpande",months:"Jul-sep",icon:"harvest"},{phase:"Blomning",months:"Aug",icon:"flower"}]},nutritionData:[{month:"Apr",N:4,P:2,K:2},{month:"Maj",N:6,P:3,K:3},{month:"Jun",N:7,P:3,K:4},{month:"Jul",N:5,P:4,K:4},{month:"Aug",N:4,P:3,K:3},{month:"Sep",N:2,P:2,K:2}],nutritionTips:[{timing:"Tidig vår",tip:"Ge en rejäl giva kompost eller brunnen kogödsel när hon vaknar i mars-april. Libbsticka är en av få kryddor som faktiskt gillar att bli bortskämd med näring."},{timing:"Försommar",tip:"En giva nässelvatten i juni ger kraftig bladtillväxt. Libbsticka svarar bra på kvävegödsel till skillnad från de flesta medelhavskryddor."},{timing:"Obs!",tip:"Libbsticka i kruka behöver mer gödsel än i friland - rötterna kan inte leta sig ut. Ge flytande näring varannan vecka under sommaren."}],companions:{good:[{id:"tomat",name:"Tomat",icon:"vegetable",why:"Libbstickans starka doft avskräcker bladlöss och spinnkvalster. Plantera i norra kanten av tomatbädden så hon inte skuggar."},{id:"bondbona",name:"Bondböna",icon:"vegetable",why:"Baljväxter fixerar kväve som den storätande libbstickan tacksamt tar del av."},{id:"timjan",name:"Timjan",icon:"herb",why:"Timjans låga växtsätt kompletterar libbstickans höjd. De stör inte varandra och lockar tillsammans massor av pollinerare."}],bad:[{id:"morot",name:"Morot",icon:"vegetable",why:"Samma familj (Apiaceae) - delar sjukdomar och skadedjur. Morotsflugan kan flytta mellan dem."},{id:"dill",name:"Dill",icon:"herb",why:"Samma familj. Dessutom konkurrerar dill dåligt med libbstickans massiva storlek."}]},rotation:{avoid:[{id:"morot",name:"Morot"},{id:"dill",name:"Dill"},{id:"persilja",name:"Persilja"},{id:"palsternacka",name:"Palsternacka"}],avoidWhy:"Flockblommiga (Apiaceae) delar jordburna sjukdomar. Men libbsticka är perenn och bör stå kvar på samma plats i 10-15 år - flytta bara om plantan blivit för stor.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodBeforeWhy:"Baljväxter berikar jorden med kväve. Libbstickans djupa pålrot luckrar sedan jorden fantastiskt.",goodAfter:[{name:"Kål"},{id:"lok",name:"Lök"}],goodAfterWhy:"När libbsticka till slut tas bort efter 10-15 år lämnar pålroten djupa kanaler i jorden. Perfekt för kål och lök som uppskattar luckrad jord."},varieties:[{name:"Libbsticka (standardart)",zones:[1,2,3,4,5,6,7,8],note:"Det finns i princip bara en sort i odling - arten i sig. Ekologiskt frö hos Lindbloms (Demeter-certifierat) och Impecta. NordFrö säljer också frö odlat utan syntetiska bekämpningsmedel. Alla ger samma kraftfulla, sellerilikande smak."}],problems:[{name:"Sellerifluga",symptom:"Bruna, pappersliknande fläckar i bladen där larverna minerar (äter sig fram inuti bladet). Två generationer per år.",fix:"Klipp bort angripna blad. Insektsnät under våren och sensommaren. Samma skadedjur som på selleri och palsternacka - växtföljd hjälper."},{name:"Bladlöss",symptom:"Gröna eller svarta löss på unga skott på våren. Klibbig honungsdagg.",fix:"Spola av med hård vattenstråle. Libbsticka är så kraftig att hon oftast växer ifrån angreppen. Gynna nyckelpigor och blomflugor."},{name:"Mjöldagg",symptom:"Vitt puder på bladen vid torrt väder och dålig luftcirkulation.",fix:"Klipp bort angripna delar. Gallra för bättre luftcirkulation. Libbsticka skjuter snabbt nya friska blad."}],goodToKnow:[{icon:"tip",title:"Maggikryddan!",text:'Libbsticka kallas "Maggikraut" (maggiört) på tyska - smaken och doften påminner slående om Maggis buljongkrydda. Men roliga faktumet: Maggi innehåller faktiskt ingen libbsticka! Libbsticka innehåller naturligt glutamat, därav den umami-rika smaken.',severity:"tip"},{icon:"tip",title:"Munkarnas krydda",text:"Libbsticka fördes till Sverige av munkar under medeltiden och odlades i klosterträdgårdarna. Förr stod det en libbsticka vid varje husmodersköksdörr - ett blad i grytan ersatte dyra buljongkryddor.",severity:"tip"},{icon:"tip",title:"Hela växten är ätbar",text:"Inte bara bladen! Roten kan kokas eller stekas som rotfrukt (smakar som kraftig selleri). Fröna används som krydda (som sellerifrö). Stjälkarna kan kanderas som konfekt!",severity:"tip"},{icon:"warning",title:"Hon blir STOR",text:"En etablerad libbsticka blir 2 meter hög och bred som en buske. Planera för det! Ge henne en plats i norra kanten av trädgårdslandet så hon inte skuggar allt annat. Klipp ner blommorna om du vill hålla henne lite i styr.",severity:"warning"},{icon:"tip",title:"Pollinatorernas favorit",text:"Libbstickans gula flockblommor är fantastiska för nyttoinsekter - speciellt parasitsteklar och blomflugor som äter bladlöss. En libbsticka i trädgården ger biologisk skadedjursbekämpning på köpet.",severity:"tip"}],sowing:{method:"both",label:"Direktsådd eller förodling",description:"Libbsticka kan förodlas inomhus eller sås direkt. Fröna gror ojämnt och långsamt (2-3 veckor), men det enklaste sättet att starta är att dela en befintlig planta - fråga en odlarkompis! En vuxen libbsticka kan enkelt delas i 3-4 bitar.",steps:["Förodling: Så 1-2 cm djupt i fuktig såjord i mars-april","Håll jämnt fuktigt och varmt (15-21°C)","Groning tar 14-21 dagar och sker ojämnt - ha tålamod","Gallra eller flytta plantorna till egna krukor vid 5 cm höjd","Härda av 1 vecka innan utplantering efter sista frost","Plantera ut med 40-60 cm avstånd - ge henne utrymme att växa!","Alternativ: Direktså utomhus i maj-juni, 1-2 cm djupt"],tips:["Delning av en etablerad planta på våren är det absolut enklaste sättet att starta. Gräv upp, dela med spade, plantera direkt","Färska frön gror mycket bättre än gamla - grobarhet sjunker snabbt. Köp nytt frö varje år","Höstsådd (september) direkt utomhus kan ge bättre groning - kylbehandlingen över vintern bryter fröets dvala naturligt"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Enkel",type:"Insektspollinerad",biennial:!1,description:"Libbsticka sätter gott om frö från och med år 2-3. Fröna mognar på sensommaren och kan samlas in genom att klippa av hela fröställningarna när de börjar bruna.",steps:["Låt 1-2 fröställningar mogna helt på plantan (augusti-september)","Klipp av när fröna börjar bruna men innan de faller av","Häng uppochner i papperspåse på torr plats","Fröna faller ner i påsen av sig själva under torkning","Rensa och förvara torrt i glasburk eller kuvert","Så helst samma höst eller nästa vår - grobarhet sjunker snabbt"],isolation:"Libbsticka är ensam i sitt släkte (Levisticum) i svensk odling - ingen risk för korspollinering med andra arter. Enda arten i sin familj hon kan korsa med finns inte i våra trädgårdar.",storageYears:"1-2 år (använd helst färskt frö)",tip:"Libbsticka självsår sig gärna om du låter fröna falla. Rensa bort oönskade plantor på våren - annars har du snart en hel libbstickskog!"},storage:{shelfLife:"Färska blad 3-5 dagar, torkade 6-12 månader",methods:[{method:"Frysning (bäst!)",icon:"snowflake",duration:"6+ månader",description:"Frysning bevarar libbstickans smak och arom bäst. Hacka bladen och frys i isbitsfack med vatten. Eller frys hela blad i påse - plocka efter behov rakt i grytan.",best:!0},{method:"Torkning",icon:"storage",duration:"6-12 månader",description:"Häng knippen uppochner på mörk, luftig plats i 1-2 veckor. Smaken ändras lite vid torkning - blir mer koncentrerad men förlorar en del fräschör. Fortfarande utmärkt som krydda.",best:!1},{method:"Färsk i kyl",icon:"water",duration:"3-5 dagar",description:"Ställ stjälkarna i ett glas vatten i kylen - som en bukett. Eller linda i fuktigt hushållspapper i plastpåse.",best:!1}],tips:["Frys portionsvis i isbitsfack - ett fack = en grytas behov av libbsticka","Roten kan skivas och torkas som krydda - stark selleriartad smak","Fröna kan användas hela som krydda, liknar sellerifrö i smak","En planta ger mer blad än du någonsin kan använda - dela med grannar och vänner!"]},harvestCalc:{minPerSqm:.5,maxPerSqm:1.5,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp bladkluster löpande, aldrig mer än halva plantan",description:"Skörda genom att klippa bladkluster med stjälk. Libbsticka är generös - hon skjuter snabbt nya skott efter skörd. Unga, ljusgröna blad har mildast smak, äldre mörkgröna blad är kraftigare.",uses:[{use:"Soppor & buljonger",tip:"DEN klassiska användningen. Ett enda blad ger en hel gryta den där djupa, umami-rika smaken som förr krävde buljongkuber. Mormors hemliga ingrediens!"},{use:"Potatis & rotfrukter",tip:"Finstrimla blad i potatissallad, potatissoppa eller rotsaksgryta. Libbsticka och potatis är ett odödligt par."},{use:"Smör & ost",tip:"Hacka fint och blanda i smör eller färskost. Libbstickesmör på nykokt potatis - rent trädgårdslyx."},{use:"Smoothies & drinkar",tip:"Oväntat men fantastiskt! Ett par blad i en grön smoothie ger en selleriartad, salt-umami ton. Eller muddla med gin och tonic."}]}};export{a as libbsticka};
